// Common memory leak: closures holding references
function createLeak() {
  let largeData = new Array(1000000).fill('x');
  return function () {
    // This closure keeps largeData alive
    console.log('still holding');
  };
}

const leakyFn = createLeak();
// largeData cannot be GC'd even though
// createLeak finished execution
